class Solution:
    def isNumber(self, s):
        i, n = 0, len(s)
        if i < n and s[i] in '+-':
            i += 1
        digits_before = False
        while i < n and s[i].isdigit():
            i += 1
            digits_before = True
        digits_after = False
        if i < n and s[i] == '.':
            i += 1
            while i < n and s[i].isdigit():
                i += 1
                digits_after = True
        if not (digits_before or digits_after):
            return False
        if i < n and s[i] in 'eE':
            i += 1
            if i < n and s[i] in '+-':
                i += 1
            exp_digits = False
            while i < n and s[i].isdigit():
                i += 1
                exp_digits = True
            if not exp_digits:
                return False
        return i == n

